#include <bits/stdc++.h>
using namespace std;
const int N=20;
int n,dp[1<<N][N],a[N][N],ans=0x3f3f3f3f;
int main()
{
    memset(dp,0x3f,sizeof(dp));
    cin>>n;
    dp[1][0]=0;
    for(int i=1;i<=n;i++)
    {
        for(int j=1;j<=n;j++)
        {
            cin>>a[i][j];
        }
    }
    int num=1<<n;
    for(int i=1;i<num;i+=2)
    {
        for(int j=0;j<n;j++)
        {
            if((i&(1<<(j)))==0) continue;
            for(int k=0;k<n;k++)
			{
				if(j==k||(!((1<<k)&i))) continue;
				dp[i][j]=min(dp[i][j],dp[i^(1<<j)][k]+a[k+1][j+1]);
			}
        }
    }
    for(int i=0;i<n;i++)
    {
        ans=min(ans,dp[num-1][i]+a[i+1][1]);
    }
    cout<<ans;
    return 0;
}
